DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(100) DEFAULT NULL,
  `telegram_id` BIGINT NOT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `training_completed_cards` int(11) NOT NULL,
  `training_completed_full` int(11) NOT NULL,
  `training_true_cards` int(11) NOT NULL,
  `intensive_completed_cards` int(11) NOT NULL,
  `intensive_completed_full` int(11) NOT NULL,
  `intensive_true_cards` int(11) NOT NULL,
  `marathon_completed_cards` int(11) NOT NULL,
  `marathon_completed_full` int(11) NOT NULL,
  `marathon_true_cards` int(11) NOT NULL,
  `week_training_completed_cards` int(11) NOT NULL,
  `week_training_completed_full` int(11) NOT NULL,
  `week_training_true_cards` int(11) NOT NULL,
  `week_intensive_completed_cards` int(11) NOT NULL,
  `week_intensive_completed_full` int(11) NOT NULL,
  `week_intensive_true_cards` int(11) NOT NULL,
  `week_marathon_completed_cards` int(11) NOT NULL,
  `week_marathon_completed_full` int(11) NOT NULL,
  `week_marathon_true_cards` int(11) NOT NULL,
  `culture_completed_cards` int(11) NOT NULL,
  `culture_completed_full` int(11) NOT NULL,
  `culture_true_cards` int(11) NOT NULL,
  `week_culture_completed_cards` int(11) NOT NULL,
  `week_culture_completed_full` int(11) NOT NULL,
  `week_culture_true_cards` int(11) NOT NULL,
  `streak_days` int(11) NOT NULL,
  `last_activity` datetime NOT NULL,
  `last_update_info` datetime NOT NULL,
  `ad_clicks_total` int(11) NOT NULL,
  `ad_clicks_week` int(11) NOT NULL,
  `ad_clicks_month` int(11) NOT NULL,
  `ad_clicked_once` int(11) NOT NULL,
  `ad_clicked_week` int(11) NOT NULL,
  `ad_clicked_month` int(11) NOT NULL,
  `ad_last_click_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `telegram_id` (`telegram_id`),
  KEY `ix_users_telegram_id` (`telegram_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


